INSERT INTO `products` VALUES (1,'Forest Ranger','forest-ranger',1,'Built for the trail and the street alike. Foam front, mesh back, and a leather patch that ages like fine timber. The cap that goes where you go.','{"specs":[{"label":"Material","value":"65% Cotton / 35% Polyester — Mesh: 100% Polyester"},{"label":"Fit","value":"Unstructured, Mid Profile"},{"label":"Closure","value":"Adjustable Snapback"},{"label":"Brim","value":"Pre-Curved"},{"label":"Origin","value":"Made in Indonesia"}],"features":["Heat-pressed leather patch","Breathable 6-panel mesh back","Moisture-wicking sweatband","One size fits most"]}','["https://images.unsplash.com/photo-1719934663694-41b6fdceb448?w=900&q=85&auto=format&fit=crop","https://images.unsplash.com/photo-1719934663722-63b567d14eea?w=900&q=85&auto=format&fit=crop"]',275000,'Hi Capstify! I want to order the Forest Ranger Trucker Cap. Please let me know the availability and how to proceed.','','',1,1,1,'2026-05-06 20:18:30');
INSERT INTO `products` VALUES (2,'Maple Standard','maple-standard',1,'The clean trucker. A foam front that holds its shape, mesh back that breathes, and a woven patch that speaks for itself. No fuss.','{"specs":[{"label":"Material","value":"60% Cotton / 40% Polyester"},{"label":"Fit","value":"Structured, Mid Profile"},{"label":"Closure","value":"Adjustable Snapback"},{"label":"Brim","value":"Pre-Curved"},{"label":"Origin","value":"Made in Indonesia"}],"features":["Woven patch label","Ventilated 6-panel mesh back","Adjustable snapback closure","One size fits most"]}','["https://images.unsplash.com/photo-1719934663722-63b567d14eea?w=900&q=85&auto=format&fit=crop","https://images.unsplash.com/photo-1719934663694-41b6fdceb448?w=900&q=85&auto=format&fit=crop"]',250000,'Hi Capstify! I want to order the Maple Standard Trucker Cap. Please let me know the availability and how to proceed.','','',1,0,2,'2026-05-06 20:18:30');
